    {
      "action": "candidate_edit",
      "title": "为 Cold Feed 添加流量规格占位符",
      "target": {
        "type": "stream",
        "id": "feed-13"
      },
      "rationale": "诊断表明 Cold Feed 缺失流量定义。补充流量占位符能提示用户输入必要的规格参数，以修复 STREAM_SPEC_MISSING 错误。",
